INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('517', '<p><strong>Reading 1</strong></p><p>Someone recently bought a lock of John Lennon''s hair for more than $48,000 Canadian dollars. The 10-centimeter (four-inch) strand of hair is about 50 years old. Hairdresser Klaus Barbuck gave Lennon a haircut in 1966 for the movie, ''How I Won the War,'' about a fictional British army troop. He saved the hair all that time. It turns out, it was a smart idea.</p><p>John Lennon was a famous British musician--one of the most famous in the world. He was one of the Beatles, perhaps the most popular rock band in history. After the Beatles broke up in 1970, Lennon went on to have an extremely successful solo career.</p><p>While he was with the Beatles, he wrote (often with fellow Beatle Paul McCartney) most of the Beatles'' biggest hits. He was also one of the band''s lead singers, so when you hear a Beatles song, chances are John Lennon wrote it and can be heard singing it.</p><p>Lennon died tragically in 1980 when he was 40 years old, but music lovers around the world still remember him and his songs, including ''A Hard Day''s Night,'' ''Help!'' and ''I Wanna Hold Your Hand'' when he was with the Beatles and ''Imagine'' and ''Give Peace a Chance'' afterwards.</p><p>Paul Fraser, who lives in Britain and collects Beatles memorabilia (things from and about the Beatles), bought the strand of hair. He paid about three times more than anyone expected, according to the British newspaper, ''The Guardian''.</p><p><strong>19. Which of the following is NOT true about John Lennon ?</strong></p>', '{"A":"He was a famous English singer and songwriter.","B":"He was a member of the Beatles until 1970.","C":"He usually wrote all of the Beatles songs by himself.","D":"He died young at the age of 40."}', 'C', '<p><strong>ตอบ 3) He usually wrote all of the Beatles songs by himself.</strong></p><p>Which of the following is NOT true about John Lennon ? ข้อใดไม่จริงเกี่ยวกับ John Lennon<br/>1. เขาเป็นนักร้องและนักแต่งเพลงชาวอังกฤษที่มีชื่อเสียง<br/>2. เขาเป็นสมาชิกวง the Beatles จนถึงปี 1970<br/>3. เขาเขียนทุกเพลงของ the Beatles ด้วยตัวเอง<br/>4. เขาเสียชีวิตตั้งแต่อายุยังน้อย เพียง 40 ปี<br/>จากเนื้อเรื่อง เขามักแต่งเพลงร่วมกับ Paul McCartney ไม่ได้แต่งเองทั้งหมด</p>', 'ก.พ.', 'ภาษาอังกฤษ', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["บทความ (Reading)"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('518', '<p><strong>Reading 1</strong></p><p>Someone recently bought a lock of John Lennon''s hair for more than $48,000 Canadian dollars. The 10-centimeter (four-inch) strand of hair is about 50 years old. Hairdresser Klaus Barbuck gave Lennon a haircut in 1966 for the movie, ''How I Won the War,'' about a fictional British army troop. He saved the hair all that time. It turns out, it was a smart idea.</p><p>John Lennon was a famous British musician--one of the most famous in the world. He was one of the Beatles, perhaps the most popular rock band in history. After the Beatles broke up in 1970, Lennon went on to have an extremely successful solo career.</p><p>While he was with the Beatles, he wrote (often with fellow Beatle Paul McCartney) most of the Beatles'' biggest hits. He was also one of the band''s lead singers, so when you hear a Beatles song, chances are John Lennon wrote it and can be heard singing it.</p><p>Lennon died tragically in 1980 when he was 40 years old, but music lovers around the world still remember him and his songs, including ''A Hard Day''s Night,'' ''Help!'' and ''I Wanna Hold Your Hand'' when he was with the Beatles and ''Imagine'' and ''Give Peace a Chance'' afterwards.</p><p>Paul Fraser, who lives in Britain and collects Beatles memorabilia (things from and about the Beatles), bought the strand of hair. He paid about three times more than anyone expected, according to the British newspaper, ''The Guardian''.</p><p><strong>20. Why did John have his hair cut ?</strong></p>', '{"A":"To give it to the hairdresser","B":"To have a modern look","C":"To look good for his new album","D":"To look like a soldier"}', 'D', '<p><strong>ตอบ 4) To look like a soldier</strong></p><p>Why did John have his hair cut ? ทำไม John ถึงตัดผมของเขา<br/>1. To give it to the hairdresser เพื่อเอาไปให้ช่างทำผม<br/>2. To have a modern look เพื่อให้ดูทันสมัย<br/>3. To look good for his new album เพื่อให้ดูดีสำหรับอัลบั้มใหม่<br/>4. To look like a soldier เพื่อให้ดูเหมือนทหาร<br/>จากเนื้อเรื่องตัดผมเพื่อแสดงภาพยนตร์เรื่อง ''How I Won the War'' ซึ่งเกี่ยวกับกองทหารบกอังกฤษ จึงต้องตัดผมเพื่อให้ดูเหมือนทหาร</p>', 'ก.พ.', 'ภาษาอังกฤษ', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["บทความ (Reading)"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('519', '<p><strong>Reading 1</strong></p><p>Someone recently bought a lock of John Lennon''s hair for more than $48,000 Canadian dollars. The 10-centimeter (four-inch) strand of hair is about 50 years old. Hairdresser Klaus Barbuck gave Lennon a haircut in 1966 for the movie, ''How I Won the War,'' about a fictional British army troop. He saved the hair all that time. It turns out, it was a smart idea.</p><p>John Lennon was a famous British musician--one of the most famous in the world. He was one of the Beatles, perhaps the most popular rock band in history. After the Beatles broke up in 1970, Lennon went on to have an extremely successful solo career.</p><p>While he was with the Beatles, he wrote (often with fellow Beatle Paul McCartney) most of the Beatles'' biggest hits. He was also one of the band''s lead singers, so when you hear a Beatles song, chances are John Lennon wrote it and can be heard singing it.</p><p>Lennon died tragically in 1980 when he was 40 years old, but music lovers around the world still remember him and his songs, including ''A Hard Day''s Night,'' ''Help!'' and ''I Wanna Hold Your Hand'' when he was with the Beatles and ''Imagine'' and ''Give Peace a Chance'' afterwards.</p><p>Paul Fraser, who lives in Britain and collects Beatles memorabilia (things from and about the Beatles), bought the strand of hair. He paid about three times more than anyone expected, according to the British newspaper, ''The Guardian''.</p><p><strong>21. What did John do after the breakup of the Beatles ?</strong></p>', '{"A":"He retired from music.","B":"He joined a different band.","C":"He pursued a career in movie acting.","D":"He continued his career as a solo musician."}', 'D', '<p><strong>ตอบ 4) He continued his career as a solo musician.</strong></p><p>What did John do after the breakup of the Beatles ? เกิดอะไรขึ้นกับ John เมื่อแยกทางกับวง the Beatles<br/>1. เขาเลิกเล่นดนตรี<br/>2. เขาเข้าร่วมวงดนตรีอื่น<br/>3. เขาประกอบอาชีพเป็นนักแสดงภาพยนตร์<br/>4. เขาดำเนินอาชีพนักดนตรีเดี่ยวต่อไป<br/>จากเนื้อเรื่อง "After the Beatles broke up in 1970, Lennon went on to have an extremely successful solo career."</p>', 'ก.พ.', 'ภาษาอังกฤษ', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["บทความ (Reading)"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('520', '<p><strong>Reading 1</strong></p><p>Someone recently bought a lock of John Lennon''s hair for more than $48,000 Canadian dollars. The 10-centimeter (four-inch) strand of hair is about 50 years old. Hairdresser Klaus Barbuck gave Lennon a haircut in 1966 for the movie, ''How I Won the War,'' about a fictional British army troop. He saved the hair all that time. It turns out, it was a smart idea.</p><p>John Lennon was a famous British musician--one of the most famous in the world. He was one of the Beatles, perhaps the most popular rock band in history. After the Beatles broke up in 1970, Lennon went on to have an extremely successful solo career.</p><p>While he was with the Beatles, he wrote (often with fellow Beatle Paul McCartney) most of the Beatles'' biggest hits. He was also one of the band''s lead singers, so when you hear a Beatles song, chances are John Lennon wrote it and can be heard singing it.</p><p>Lennon died tragically in 1980 when he was 40 years old, but music lovers around the world still remember him and his songs, including ''A Hard Day''s Night,'' ''Help!'' and ''I Wanna Hold Your Hand'' when he was with the Beatles and ''Imagine'' and ''Give Peace a Chance'' afterwards.</p><p>Paul Fraser, who lives in Britain and collects Beatles memorabilia (things from and about the Beatles), bought the strand of hair. He paid about three times more than anyone expected, according to the British newspaper, ''The Guardian''.</p><p><strong>22. Why was a lock of Lennon''s hair worth a lot of money ?</strong></p>', '{"A":"It was very old.","B":"It was sought after by collectors.","C":"It was cut by hairdresser Klaus Barbuck.","D":"It was written about in the Guardian."}', 'B', '<p><strong>ตอบ 2) It was sought after by collectors.</strong></p><p>Why was a lock of Lennon''s hair worth a lot of money ? ทำไมเส้นผมของ Lennon ถึงมีมูลค่าเป็นเงินมากมาย<br/>1. มันเก่ามาก<br/>2. มันเป็นที่ต้องการของนักสะสม<br/>3. มันถูกตัดแต่งโดยช่างตัดผมชื่อ Klaus Barbuck<br/>4. มันถูกเขียนถึงในหนังสือพิมพ์ the Guardian<br/>จากเนื้อเรื่อง Paul Fraser ผู้ซึ่งสะสมของที่ระลึกของ Beatles เป็นผู้ซื้อเส้นผมนี้ไปในราคาสูง</p>', 'ก.พ.', 'ภาษาอังกฤษ', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["บทความ (Reading)"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('521', '<p><strong>Reading 1</strong></p><p>Someone recently bought a lock of John Lennon''s hair for more than $48,000 Canadian dollars. The 10-centimeter (four-inch) strand of hair is about 50 years old. Hairdresser Klaus Barbuck gave Lennon a haircut in 1966 for the movie, ''How I Won the War,'' about a fictional British army troop. He saved the hair all that time. It turns out, it was a smart idea.</p><p>John Lennon was a famous British musician--one of the most famous in the world. He was one of the Beatles, perhaps the most popular rock band in history. After the Beatles broke up in 1970, Lennon went on to have an extremely successful solo career.</p><p>While he was with the Beatles, he wrote (often with fellow Beatle Paul McCartney) most of the Beatles'' biggest hits. He was also one of the band''s lead singers, so when you hear a Beatles song, chances are John Lennon wrote it and can be heard singing it.</p><p>Lennon died tragically in 1980 when he was 40 years old, but music lovers around the world still remember him and his songs, including ''A Hard Day''s Night,'' ''Help!'' and ''I Wanna Hold Your Hand'' when he was with the Beatles and ''Imagine'' and ''Give Peace a Chance'' afterwards.</p><p>Paul Fraser, who lives in Britain and collects Beatles memorabilia (things from and about the Beatles), bought the strand of hair. He paid about three times more than anyone expected, according to the British newspaper, ''The Guardian''.</p><p><strong>23. Which of the following is a solo John Lennon song ?</strong></p>', '{"A":"Help","B":"Give Peace a Chance","C":"A Hard Day''s Night","D":"I Wanna Hold Your Hand"}', 'B', '<p><strong>ตอบ 2) Give Peace a Chance</strong></p><p>Which of the following is a solo John Lennon song ? เพลงในข้อใดเป็นเพลงเดี่ยวของ John Lennon<br/>(เนื้อหาจากย่อหน้าที่ 4) เพลงที่เป็นเพลงเดี่ยวคือ ''Imagine'' และ ''Give Peace a Chance''</p>', 'ก.พ.', 'ภาษาอังกฤษ', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["บทความ (Reading)"]', '2559');
